import { IMessageComposer } from '@nitrots/nitro-renderer';

export class GangInviteResponseComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(accepted: boolean, inviterId: number) {
        this._data = [accepted, inviterId];
        console.log('[📤] GangInviteResponseComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}